import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import "../css/Login.css";
import { supabase } from "../services/supabaseClient";

export default function Denuncias() {
    const [pesquisarDenuncia, setPesquisarDenuncia] = useState('');
    const [denuncias, setDenuncias] = useState([]);
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        fetchDenuncias();
    }, []);

    const fetchDenuncias = async () => {
        setLoading(true);

        const { data, error } = await supabase
            .from('denuncias')
            .select('*')
            .order('id', { ascending: false });

        setLoading(false);

        if (error) {
            console.error('Erro ao buscar denúncias:', error);
            return;
        }

        setDenuncias(data || []);
    };

    const denunciasFiltradas = denuncias.filter((denuncia) => {
        const termo = pesquisarDenuncia.toLowerCase();
        return (
            denuncia.categoria?.toLowerCase().includes(termo) ||
            denuncia.descricao?.toLowerCase().includes(termo) ||
            denuncia.urgencia?.toLowerCase().includes(termo) ||
            denuncia.protocolo?.toLowerCase().includes(termo) ||
            denuncia.endereco?.toLowerCase().includes(termo)
        );
    });

    return (
        <div className="conta">
            <h2>Minhas Denuncias</h2>
            <p>Acompanhe os status e detalhes das suas solicitações ativas e concluídas.</p>
            <div>
                <input
                    type="text"
                    value={pesquisarDenuncia}
                    onChange={(e) => setPesquisarDenuncia(e.target.value)}
                    placeholder="Buscar por protocolo, título ou endereço..."
                />
            </div>

            {loading ? (
                <p>Carregando denúncias...</p>
            ) : (
                <div className="lista-denuncias">
                    {denunciasFiltradas.length === 0 ? (
                        <p>Nenhuma denúncia encontrada.</p>
                    ) : (
                        denunciasFiltradas.map((denuncia) => (
                            <div key={denuncia.id} className="card-denuncia">
                                <h3>{denuncia.categoria || 'Sem categoria'}</h3>
                                <p>{denuncia.descricao}</p>
                                <p><strong>Urgência:</strong> {denuncia.urgencia || 'Não informada'}</p>
                                <p><strong>Data do fato:</strong> {denuncia.data || 'Não informada'}</p>
                                {denuncia.protocolo && <p><strong>Protocolo:</strong> {denuncia.protocolo}</p>}
                            </div>
                        ))
                    )}
                </div>
            )}

            <Link to="/novadenuncias">+</Link>
        </div>
    );
}
