import { useNavigate, Link } from "react-router-dom";
import "../css/Departamentos.css";
import { useState, useEffect } from "react";
import { api } from "../typescript/teste";

export default function Departamentos() {
    const [departamentos] = useState([
        { id: 1, nome: "Secretaria de Urbanismo", desc: "Planejamento urbano, emissão de alvarás, fiscalização de obras." },
        { id: 2, nome: "Saúde", desc: "Gestão da rede municipal de saúde, UBS, hospitais, vacinação." },
        { id: 3, nome: "Educação", desc: "Administração da rede de ensino fundamental e infantil, transporte escolar." },
        { id: 4, nome: "Sede Administrativa", desc: "Gabinete do Prefeito, finanças, recursos humanos, licitações." }
    ]);

    const [listaDepartamentos, setListaDepartamentos] = useState([]);

    useEffect(() => {
        api.get('/departamentos')
            .then(res => setListaDepartamentos(res.data))
            .catch(err => console.error(err));
    }, []);

    const [departamento, setDepartamento] = useState('');
    return (
        <div className="sessao">
            <h2>Departamentos</h2>
            <p>Acesse informações, serviços e contatos de todas as secretarias e divisões da administração municipal.</p>
            
            <div className="grid-departamentos">
                {departamentos.map((dep) => (
                    <div key={dep.id} className="card-departamento">
                        <h3>{dep.nome}</h3>
                        <p>{dep.desc}</p>
                        <button>Ver Detalhes →</button>
                    </div>
                ))}
            </div>
        </div>
    );
}