import { useState } from "react";
import { useNavigate } from "react-router-dom";
import "../css/NovaDenuncia.css";
import { supabase } from "../services/supabaseClient";

export default function NovaDenuncia() {
    const [categoria, setCategoria] = useState('');
    const [descricao, setDescricao] = useState('');
    const [data, setData] = useState('');
    const [urgencia, setUrgencia] = useState('Média');
    const navigate = useNavigate();

    const registrarDenuncia = async () => {
        if (!categoria || !descricao || !data || !urgencia) {
            alert('Preencha todos os campos antes de enviar.');
            return;
        }

        const { error } = await supabase.from('denuncias').insert([
            {
                categoria,
                descricao,
                data,
                urgencia,
            },
        ]);

        if (error) {
            alert('Erro na conexão: ' + error.message);
            return;
        }

        navigate('/denuncias');
    };

    return (
        <div className="container-principal">
            <div className="formulario-secao">
                <h2>Nova Solicitação</h2>
                
                <section>
                    <p>Categoria do Serviço</p>
                    <select 
                        value={categoria} 
                        onChange={(e) => setCategoria(e.target.value)}
                    >
                        <option value="">Selecione...</option>
                        <option value="limpeza">Limpeza Urbana</option>
                        <option value="infra">Infraestrutura</option>
                        <option value="buracos">Buracos</option>
                    </select>
                </section>

                <section>
                    <p>Descrição Detalhada</p>
                    <textarea 
                        value={descricao} 
                        onChange={(e) => setDescricao(e.target.value)}
                        placeholder="Descreva o problema..." 
                    />
                </section>

                <section>
                    <p>Data de Ocorrência</p>
                    <input type="date" value={data} onChange={(e) => setData(e.target.value)} />
                </section>
                <section>
                    <p>Nivel de Urgencia</p>
                    <select
                        value={urgencia}
                        onChange={(e) => setUrgencia(e.target.value)}
                    >
                        <option value="">Selecionar...</option>
                        <option value="azul">Não Urgente (Azul)</option>
                        <option value="verde">Pouco Urgente (Verde)</option>
                        <option value="amarelo">Urgente (Amarelo)</option>
                        <option value="laranja">Muito Urgente (Laranja)</option>
                        <option value="vermelho">Emergência (Vermelho)</option>
                    </select>
                </section>
                <section>
                    <p>Anexar Fotos/Documentos</p>
                </section>

                <div className="bt-controle">
                    <button onClick={() => navigate('/')}>Cancelar</button>
                    <button onClick={registrarDenuncia}>Registrar Denúncia</button>
                </div>
            </div>

            <div className="mapa-secao">
                <p>Mapa de Localização</p>
            </div>
        </div>
    );
}